-- ----------------------------
-- Table structure for fx_encode_history
-- ----------------------------
DROP TABLE IF EXISTS `fx_encode_history`;
CREATE TABLE `fx_encode_history`  (
  `id` bigint NOT NULL COMMENT '历史记录 ID（雪花算法生成）',
  `rule_id` bigint NOT NULL COMMENT '规则 ID（关联 fx_encode_rule.id）',
  `rule_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则编码（冗余字段，便于查询）',
  `biz_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '业务类型',
  `generated_code` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '生成的编码',
  `biz_id` bigint NULL DEFAULT NULL COMMENT '关联业务 ID（如订单 ID、合同 ID 等）',
  `biz_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '关联业务单号',
  `sequence_value` int NULL DEFAULT NULL COMMENT '生成时的序列号值',
  `reset_flag` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '重置标识（用于标识重置周期，如：20260410, 202604 等）',
  `operator_id` bigint NULL DEFAULT NULL COMMENT '操作人 ID',
  `operator_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作人姓名',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注说明',
  `tenant_id` bigint NOT NULL DEFAULT 0 COMMENT '租户 ID（0 表示公共数据）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新人',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0=未删除，1=已删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_rule_id`(`rule_id` ASC) USING BTREE COMMENT '规则 ID 索引',
  INDEX `idx_rule_code`(`rule_code` ASC) USING BTREE COMMENT '规则编码索引',
  INDEX `idx_biz_type`(`biz_type` ASC) USING BTREE COMMENT '业务类型索引',
  INDEX `idx_generated_code`(`generated_code` ASC) USING BTREE COMMENT '生成编码索引',
  INDEX `idx_biz_id`(`biz_id` ASC) USING BTREE COMMENT '关联业务 ID 索引',
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE COMMENT '创建时间索引',
  INDEX `idx_tenant_id`(`tenant_id` ASC) USING BTREE COMMENT '租户 ID 索引',
  CONSTRAINT `fk_encode_history_rule` FOREIGN KEY (`rule_id`) REFERENCES `fx_encode_rule` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '编码历史记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of fx_encode_history
-- ----------------------------

-- ----------------------------
-- Table structure for fx_encode_rule
-- ----------------------------
DROP TABLE IF EXISTS `fx_encode_rule`;
CREATE TABLE `fx_encode_rule`  (
  `id` bigint NOT NULL COMMENT '编码规则 ID（雪花算法生成）',
  `rule_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则名称',
  `module` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '适用模块',
  `prefix` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '编码前缀',
  `rule_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则编码（唯一标识，用于代码调用）',
  `biz_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '业务类型（如：ORDER, CONTRACT, INVOICE 等）',
  `rule_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '规则描述',
  `encode_prefix` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '编码前缀（固定字符，如：ORD, CNT 等）',
  `encode_suffix` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '编码后缀（固定字符）',
  `total_length` int NULL DEFAULT NULL COMMENT '编码总长度（包含前缀、后缀、序列号等）',
  `date_format` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '日期格式（如：yyyyMMdd, yyMM, yyyy 等）',
  `serial_length` int NULL DEFAULT 4 COMMENT '流水位数',
  `reset_cycle` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'DAILY' COMMENT '流水重置周期',
  `current_serial` int NULL DEFAULT 0 COMMENT '当前流水号',
  `sequence_length` int NULL DEFAULT 6 COMMENT '序列号长度（默认 6 位）',
  `sequence_start` int NULL DEFAULT 1 COMMENT '序列号起始值（默认从 1 开始）',
  `padding_char` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '填充字符（序列号不足长度时的填充字符）',
  `padding_side` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'LEFT' COMMENT '填充方向：LEFT=左侧填充，RIGHT=右侧填充',
  `reset_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'NONE' COMMENT '重置类型：NONE=不重置，DAILY=每日重置，MONTHLY=每月重置，YEARLY=每年重置',
  `reset_sequence` tinyint NULL DEFAULT 1 COMMENT '重置后序列号是否归 1：0=不归 1，1=归 1',
  `is_enabled` tinyint NOT NULL DEFAULT 1 COMMENT '是否启用：0=禁用，1=启用',
  `sort_order` int NULL DEFAULT 0 COMMENT '排序号',
  `is_default` tinyint NULL DEFAULT 0 COMMENT '是否默认规则：0=否，1=是（同一业务类型只能有一个默认规则）',
  `priority` int NULL DEFAULT 0 COMMENT '优先级（数字越小优先级越高，用于多规则匹配）',
  `effective_date` date NULL DEFAULT NULL COMMENT '生效日期',
  `expiry_date` date NULL DEFAULT NULL COMMENT '失效日期',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注说明',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：0=停用，1=启用',
  `tenant_id` bigint NOT NULL DEFAULT 0 COMMENT '租户 ID（0 表示公共数据，所有租户共享）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新人',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0=未删除，1=已删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_rule_code`(`rule_code` ASC) USING BTREE COMMENT '规则编码唯一索引',
  INDEX `idx_biz_type`(`biz_type` ASC) USING BTREE COMMENT '业务类型索引',
  INDEX `idx_rule_name`(`rule_name` ASC) USING BTREE COMMENT '规则名称索引',
  INDEX `idx_status`(`status` ASC) USING BTREE COMMENT '状态索引',
  INDEX `idx_is_enabled`(`is_enabled` ASC) USING BTREE COMMENT '是否启用索引',
  INDEX `idx_effective_date`(`effective_date` ASC) USING BTREE COMMENT '生效日期索引',
  INDEX `idx_tenant_id`(`tenant_id` ASC) USING BTREE COMMENT '租户 ID 索引'
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '编码规则主表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of fx_encode_rule
-- ----------------------------

-- ----------------------------
-- Table structure for fx_encode_rule_detail
-- ----------------------------
DROP TABLE IF EXISTS `fx_encode_rule_detail`;
CREATE TABLE `fx_encode_rule_detail`  (
  `id` bigint NOT NULL COMMENT '明细 ID（雪花算法生成）',
  `rule_id` bigint NOT NULL COMMENT '规则 ID（关联 fx_encode_rule.id）',
  `segment_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '段类型：FIXED=固定字符，DATE=日期，SEQUENCE=序列号，VARIABLE=变量',
  `segment_value` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '段值（固定字符段的实际值，或变量段的变量名）',
  `connector` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '连接符',
  `segment_length` int NULL DEFAULT NULL COMMENT '段长度（固定字符段为字符长度，日期段为格式长度，序列号为数字位数）',
  `date_format` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '日期格式（仅日期段使用，如：yyyy, MM, dd, HHmmss 等）',
  `sequence_start` int NULL DEFAULT 1 COMMENT '序列号起始值（仅序列段使用）',
  `padding_char` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '填充字符（序列号不足长度时的填充字符）',
  `padding_side` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'LEFT' COMMENT '填充方向：LEFT=左侧填充，RIGHT=右侧填充',
  `segment_order` int NOT NULL COMMENT '段顺序（从 1 开始，决定各段在编码中的位置）',
  `is_required` tinyint NOT NULL DEFAULT 1 COMMENT '是否必填：0=可选，1=必填',
  `condition_expression` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '条件表达式',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '段描述',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注说明',
  `tenant_id` bigint NOT NULL DEFAULT 0 COMMENT '租户 ID（0 表示公共数据）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新人',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0=未删除，1=已删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_rule_id`(`rule_id` ASC) USING BTREE COMMENT '规则 ID 索引',
  INDEX `idx_segment_type`(`segment_type` ASC) USING BTREE COMMENT '段类型索引',
  INDEX `idx_segment_order`(`segment_order` ASC) USING BTREE COMMENT '段顺序索引',
  INDEX `idx_tenant_id`(`tenant_id` ASC) USING BTREE COMMENT '租户 ID 索引',
  CONSTRAINT `fk_encode_rule_detail` FOREIGN KEY (`rule_id`) REFERENCES `fx_encode_rule` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '编码规则明细表' ROW_FORMAT = DYNAMIC;

