CREATE PROCEDURE `upgrade_supplier_common_ids_20260426`()
BEGIN
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'forgex_common'
      AND table_name = 'fx_table_config'
      AND column_name = 'id'
      AND extra NOT LIKE '%auto_increment%'
  ) THEN
    ALTER TABLE `forgex_common`.`fx_table_config`
      MODIFY COLUMN `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键 ID';
  END IF;

  IF EXISTS (
