INSERT INTO `fx_i18n_message` VALUES (202604260100000001, 'basic', 'SUPPLIER_CODE_EXISTS', '{\"en-US\": \"Supplier code already exists\", \"ja-JP\": \"サプライヤーコードは既に存在します\", \"ko-KR\": \"공급업체 코드가 이미 존재합니다\", \"zh-CN\": \"供应商编码已存在\", \"zh-TW\": \"供應商編碼已存在\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000002, 'basic', 'SUPPLIER_NOT_FOUND', '{\"en-US\": \"Supplier does not exist\", \"ja-JP\": \"サプライヤーが存在しません\", \"ko-KR\": \"공급업체가 존재하지 않습니다\", \"zh-CN\": \"供应商不存在\", \"zh-TW\": \"供應商不存在\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000003, 'basic', 'SUPPLIER_CODE_IMMUTABLE', '{\"en-US\": \"Supplier code cannot be changed after creation\", \"ja-JP\": \"作成後にサプライヤーコードは変更できません\", \"ko-KR\": \"공급업체 코드는 생성 후 변경할 수 없습니다\", \"zh-CN\": \"供应商编码创建后不可修改\", \"zh-TW\": \"供應商編碼建立後不可修改\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000004, 'basic', 'SUPPLIER_LINKED_TENANT_DELETE_FORBIDDEN', '{\"en-US\": \"Suppliers linked to a tenant cannot be deleted\", \"ja-JP\": \"テナントに関連付けられたサプライヤーは削除できません\", \"ko-KR\": \"테넌트와 연결된 공급업체는 삭제할 수 없습니다\", \"zh-CN\": \"已关联租户的供应商不允许删除\", \"zh-TW\": \"已關聯租戶的供應商不允許刪除\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000005, 'basic', 'SUPPLIER_LINKED_TENANT_NOT_FOUND', '{\"en-US\": \"The supplier has a linked tenant code, but the system tenant does not exist\", \"ja-JP\": \"サプライヤーには関連テナントコードがありますが、システムテナントが存在しません\", \"ko-KR\": \"공급업체에 연결된 테넌트 코드가 있지만 시스템 테넌트가 존재하지 않습니다\", \"zh-CN\": \"供应商已存在关联租户编号，但系统租户不存在\", \"zh-TW\": \"供應商已有關聯租戶編號，但系統租戶不存在\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000006, 'basic', 'SUPPLIER_TENANT_CODE_OCCUPIED', '{\"en-US\": \"Tenant code is already used by another supplier\", \"ja-JP\": \"テナントコードは別のサプライヤーで使用されています\", \"ko-KR\": \"테넌트 코드가 다른 공급업체에서 이미 사용 중입니다\", \"zh-CN\": \"租户编码已被其它供应商占用\", \"zh-TW\": \"租戶編碼已被其他供應商使用\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000007, 'basic', 'SUPPLIER_TENANT_CREATE_FAILED', '{\"en-US\": \"Failed to create supplier tenant\", \"ja-JP\": \"サプライヤーテナントの作成に失敗しました\", \"ko-KR\": \"공급업체 테넌트 생성에 실패했습니다\", \"zh-CN\": \"创建供应商租户失败\", \"zh-TW\": \"建立供應商租戶失敗\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000008, 'basic', 'SUPPLIER_ID_REQUIRED', '{\"en-US\": \"Supplier ID cannot be empty\", \"ja-JP\": \"サプライヤーIDは空にできません\", \"ko-KR\": \"공급업체 ID는 비워둘 수 없습니다\", \"zh-CN\": \"供应商 ID 不能为空\", \"zh-TW\": \"供應商 ID 不能為空\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000009, 'basic', 'SUPPLIER_REVIEW_NONE_FORBIDDEN', '{\"en-US\": \"Review cannot be started when review is not required\", \"ja-JP\": \"審査不要の状態では審査を開始できません\", \"ko-KR\": \"검토 불필요 상태에서는 검토를 시작할 수 없습니다\", \"zh-CN\": \"无需审查状态不允许发起审查\", \"zh-TW\": \"無需審查狀態不允許發起審查\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000010, 'basic', 'SUPPLIER_REVIEW_PROCESSING_FORBIDDEN', '{\"en-US\": \"A supplier under review cannot be submitted for review again\", \"ja-JP\": \"審査中のサプライヤーは再度審査を開始できません\", \"ko-KR\": \"검토 중인 공급업체는 다시 검토를 시작할 수 없습니다\", \"zh-CN\": \"审查中的供应商不允许再次发起审查\", \"zh-TW\": \"審查中的供應商不允許再次發起審查\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000011, 'basic', 'SUPPLIER_REVIEW_ONLY_PENDING', '{\"en-US\": \"Only pending suppliers can be submitted for review\", \"ja-JP\": \"未審査のサプライヤーのみ審査を開始できます\", \"ko-KR\": \"미검토 공급업체만 검토를 시작할 수 있습니다\", \"zh-CN\": \"仅未审查供应商允许发起审查\", \"zh-TW\": \"僅未審查供應商允許發起審查\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000012, 'basic', 'SUPPLIER_REVIEW_START_FAILED', '{\"en-US\": \"Failed to start supplier qualification review\", \"ja-JP\": \"サプライヤー資格審査の開始に失敗しました\", \"ko-KR\": \"공급업체 자격 검토 시작에 실패했습니다\", \"zh-CN\": \"发起供应商资质审查失败\", \"zh-TW\": \"發起供應商資質審查失敗\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000013, 'basic', 'SUPPLIER_REVIEW_CALLBACK_SUPPLIER_ID_MISSING', '{\"en-US\": \"Supplier review callback is missing supplierId\", \"ja-JP\": \"サプライヤー審査コールバックに supplierId がありません\", \"ko-KR\": \"공급업체 검토 콜백에 supplierId가 없습니다\", \"zh-CN\": \"供应商审查回调缺少 supplierId\", \"zh-TW\": \"供應商審查回調缺少 supplierId\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000014, 'basic', 'SUPPLIER_THIRD_PARTY_SYNC_FAILED', '{\"en-US\": \"Supplier third-party sync failed\", \"ja-JP\": \"サプライヤーのサードパーティ同期に失敗しました\", \"ko-KR\": \"공급업체 타사 동기화에 실패했습니다\", \"zh-CN\": \"供应商第三方同步失败\", \"zh-TW\": \"供應商第三方同步失敗\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000015, 'basic', 'SUPPLIER_IMPORT_FILE_REQUIRED', '{\"en-US\": \"Import file cannot be empty\", \"ja-JP\": \"インポートファイルは空にできません\", \"ko-KR\": \"가져오기 파일은 비워둘 수 없습니다\", \"zh-CN\": \"导入文件不能为空\", \"zh-TW\": \"匯入檔案不能為空\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000016, 'basic', 'SUPPLIER_PARAM_REQUIRED', '{\"en-US\": \"Supplier parameters cannot be empty\", \"ja-JP\": \"サプライヤーパラメータは空にできません\", \"ko-KR\": \"공급업체 매개변수는 비워둘 수 없습니다\", \"zh-CN\": \"供应商参数不能为空\", \"zh-TW\": \"供應商參數不能為空\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000017, 'basic', 'SUPPLIER_CODE_REQUIRED', '{\"en-US\": \"Supplier code cannot be empty\", \"ja-JP\": \"サプライヤーコードは空にできません\", \"ko-KR\": \"공급업체 코드는 비워둘 수 없습니다\", \"zh-CN\": \"供应商编码不能为空\", \"zh-TW\": \"供應商編碼不能為空\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000018, 'basic', 'SUPPLIER_FULL_NAME_REQUIRED', '{\"en-US\": \"Supplier full name cannot be empty\", \"ja-JP\": \"サプライヤー正式名称は空にできません\", \"ko-KR\": \"공급업체 전체 이름은 비워둘 수 없습니다\", \"zh-CN\": \"供应商全称不能为空\", \"zh-TW\": \"供應商全稱不能為空\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000019, 'basic', 'SUPPLIER_DATA_REQUIRED', '{\"en-US\": \"Supplier data cannot be empty\", \"ja-JP\": \"サプライヤーデータは空にできません\", \"ko-KR\": \"공급업체 데이터는 비워둘 수 없습니다\", \"zh-CN\": \"供应商数据不能为空\", \"zh-TW\": \"供應商資料不能為空\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000020, 'basic', 'SUPPLIER_DEFAULT_TAX_RATE_RANGE', '{\"en-US\": \"Default tax rate must be between 0 and 100\", \"ja-JP\": \"デフォルト税率は0から100の間である必要があります\", \"ko-KR\": \"기본 세율은 0에서 100 사이여야 합니다\", \"zh-CN\": \"默认税率必须在 0 到 100 之间\", \"zh-TW\": \"預設稅率必須在 0 到 100 之間\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000021, 'basic', 'SUPPLIER_FIELD_VALUE_INVALID', '{\"en-US\": \"Invalid value for {0}: {1}\", \"ja-JP\": \"{0} の値が無効です：{1}\", \"ko-KR\": \"{0} 값이 올바르지 않습니다: {1}\", \"zh-CN\": \"{0}值非法：{1}\", \"zh-TW\": \"{0}值非法：{1}\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000022, 'basic', 'SUPPLIER_REVIEW_FORM_SERIALIZE_FAILED', '{\"en-US\": \"Failed to serialize supplier review form\", \"ja-JP\": \"サプライヤー審査フォームのシリアライズに失敗しました\", \"ko-KR\": \"공급업체 검토 양식 직렬화에 실패했습니다\", \"zh-CN\": \"供应商审查表单序列化失败\", \"zh-TW\": \"供應商審查表單序列化失敗\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000023, 'basic', 'SUPPLIER_REVIEW_CALLBACK_FORM_PARSE_FAILED', '{\"en-US\": \"Failed to parse supplier review callback form\", \"ja-JP\": \"サプライヤー審査コールバックフォームの解析に失敗しました\", \"ko-KR\": \"공급업체 검토 콜백 양식 파싱에 실패했습니다\", \"zh-CN\": \"供应商审查回调表单解析失败\", \"zh-TW\": \"供應商審查回調表單解析失敗\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000024, 'basic', 'SUPPLIER_IMPORT_MAIN_SHEET_MISSING', '{\"en-US\": \"Import file is missing the main sheet\", \"ja-JP\": \"インポートファイルにメインシートがありません\", \"ko-KR\": \"가져오기 파일에 기본 시트가 없습니다\", \"zh-CN\": \"导入文件缺少主表 sheet\", \"zh-TW\": \"匯入檔案缺少主表 sheet\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000025, 'basic', 'SUPPLIER_IMPORT_MAIN_CODE_DUPLICATED', '{\"en-US\": \"Duplicate supplier code in main sheet: {0}\", \"ja-JP\": \"メインシートのサプライヤーコードが重複しています：{0}\", \"ko-KR\": \"기본 시트의 공급업체 코드가 중복되었습니다: {0}\", \"zh-CN\": \"主表供应商编码重复：{0}\", \"zh-TW\": \"主表供應商編碼重複：{0}\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000026, 'basic', 'SUPPLIER_IMPORT_MAIN_SHEET_EMPTY', '{\"en-US\": \"The main sheet in the import file cannot be empty\", \"ja-JP\": \"インポートファイルのメインシートは空にできません\", \"ko-KR\": \"가져오기 파일의 기본 시트는 비워둘 수 없습니다\", \"zh-CN\": \"导入文件主表不能为空\", \"zh-TW\": \"匯入檔案主表不能為空\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000027, 'basic', 'SUPPLIER_IMPORT_ORPHAN_CODE', '{\"en-US\": \"Orphan supplier code found in {0} sheet row {1}: {2}\", \"ja-JP\": \"{0} シートの {1} 行目に孤立したサプライヤーコードがあります：{2}\", \"ko-KR\": \"{0} 시트 {1}행에 연결되지 않은 공급업체 코드가 있습니다: {2}\", \"zh-CN\": \"{0} sheet 第 {1} 行存在孤儿供应商编码：{2}\", \"zh-TW\": \"{0} sheet 第 {1} 行存在孤兒供應商編碼：{2}\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (202604260100000028, 'basic', 'SUPPLIER_DATE_FORMAT_INVALID', '{\"en-US\": \"Invalid date format: {0}\", \"ja-JP\": \"無効な日付形式：{0}\", \"ko-KR\": \"잘못된 날짜 형식: {0}\", \"zh-CN\": \"非法日期格式：{0}\", \"zh-TW\": \"非法日期格式：{0}\"}', 1, 1, NULL, '2026-04-26 18:52:32', NULL, '2026-04-26 18:52:32', 0, NULL);
