INSERT INTO `fx_i18n_message` VALUES (4000000000000000908, 'basic', 'BARCODE_EXPIRED', '{\"en-US\": \"Barcode has expired\", \"ja-JP\": \"バーコードは失効しています\", \"ko-KR\": \"바코드가 만료되었습니다\", \"zh-CN\": \"条码已失效\", \"zh-TW\": \"條碼已失效\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000909, 'basic', 'BARCODE_VOIDED', '{\"en-US\": \"Barcode has been voided\", \"ja-JP\": \"バーコードは無効化されています\", \"ko-KR\": \"바코드가 폐기되었습니다\", \"zh-CN\": \"条码已作废\", \"zh-TW\": \"條碼已作廢\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000910, 'basic', 'LABEL_TEMPLATE_NOT_FOUND', '{\"en-US\": \"Template does not exist\", \"ja-JP\": \"テンプレートが存在しません\", \"ko-KR\": \"템플릿이 존재하지 않습니다\", \"zh-CN\": \"模板不存在\", \"zh-TW\": \"模板不存在\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000911, 'basic', 'LABEL_TEMPLATE_NOT_FOUND_WITH_ID', '{\"en-US\": \"Template does not exist, ID: {0}\", \"ja-JP\": \"テンプレートが存在しません。ID: {0}\", \"ko-KR\": \"템플릿이 존재하지 않습니다. ID: {0}\", \"zh-CN\": \"模板不存在，ID: {0}\", \"zh-TW\": \"模板不存在，ID: {0}\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000912, 'basic', 'LABEL_TEMPLATE_ACCESS_DENIED', '{\"en-US\": \"No permission to access this template. Template tenant ID: {0}, current tenant ID: {1}\", \"ja-JP\": \"このテンプレートにアクセスする権限がありません。テンプレートテナントID: {0}、現在のテナントID: {1}\", \"ko-KR\": \"이 템플릿에 접근할 권한이 없습니다. 템플릿 테넌트 ID: {0}, 현재 테넌트 ID: {1}\", \"zh-CN\": \"无权访问该模板，模板租户ID: {0}，当前租户ID: {1}\", \"zh-TW\": \"無權存取該模板，模板租戶ID: {0}，目前租戶ID: {1}\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000913, 'basic', 'LABEL_TEMPLATE_CODE_EXISTS', '{\"en-US\": \"Template code already exists: {0}\", \"ja-JP\": \"テンプレートコードは既に存在します: {0}\", \"ko-KR\": \"템플릿 코드가 이미 존재합니다: {0}\", \"zh-CN\": \"模板编码已存在：{0}\", \"zh-TW\": \"模板編碼已存在：{0}\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000914, 'basic', 'LABEL_TEMPLATE_TYPE_MISMATCH', '{\"en-US\": \"Template type does not match\", \"ja-JP\": \"テンプレートタイプが一致しません\", \"ko-KR\": \"템플릿 유형이 일치하지 않습니다\", \"zh-CN\": \"模板类型不匹配\", \"zh-TW\": \"模板類型不匹配\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000915, 'basic', 'LABEL_TEMPLATE_DISABLED', '{\"en-US\": \"Template is disabled and cannot be printed\", \"ja-JP\": \"テンプレートは無効化されているため印刷できません\", \"ko-KR\": \"템플릿이 비활성화되어 인쇄할 수 없습니다\", \"zh-CN\": \"模板已禁用，无法打印\", \"zh-TW\": \"模板已停用，無法列印\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000916, 'basic', 'LABEL_TEMPLATE_AVAILABLE_NOT_FOUND', '{\"en-US\": \"No available template found\", \"ja-JP\": \"利用可能なテンプレートが見つかりません\", \"ko-KR\": \"사용 가능한 템플릿을 찾을 수 없습니다\", \"zh-CN\": \"未找到可用模板\", \"zh-TW\": \"未找到可用模板\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000917, 'basic', 'LABEL_TEMPLATE_CONFIG_MISSING', '{\"en-US\": \"No available template found. Please check the template configuration.\", \"ja-JP\": \"利用可能なテンプレートが見つかりません。テンプレート設定を確認してください。\", \"ko-KR\": \"사용 가능한 템플릿을 찾을 수 없습니다. 템플릿 설정을 확인하세요.\", \"zh-CN\": \"未找到可用模板，请检查模板配置\", \"zh-TW\": \"未找到可用模板，請檢查模板設定\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000918, 'basic', 'LABEL_BINDING_TYPE_INVALID', '{\"en-US\": \"Invalid binding type: {0}\", \"ja-JP\": \"無効なバインドタイプです: {0}\", \"ko-KR\": \"유효하지 않은 바인딩 유형입니다: {0}\", \"zh-CN\": \"无效的绑定类型: {0}\", \"zh-TW\": \"無效的綁定類型: {0}\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000919, 'basic', 'LABEL_BINDING_EXISTS', '{\"en-US\": \"This binding already exists\", \"ja-JP\": \"このバインド関係は既に存在します\", \"ko-KR\": \"해당 바인딩 관계가 이미 존재합니다\", \"zh-CN\": \"该绑定关系已存在\", \"zh-TW\": \"該綁定關係已存在\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000920, 'basic', 'LABEL_BINDING_NOT_FOUND', '{\"en-US\": \"Binding does not exist\", \"ja-JP\": \"バインド関係が存在しません\", \"ko-KR\": \"바인딩 관계가 존재하지 않습니다\", \"zh-CN\": \"绑定关系不存在\", \"zh-TW\": \"綁定關係不存在\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000921, 'basic', 'LABEL_PREVIEW_LIMIT_EXCEEDED', '{\"en-US\": \"Preview supports up to 10 labels\", \"ja-JP\": \"プレビューは最大10枚まで対応しています\", \"ko-KR\": \"미리보기는 최대 10장까지 지원됩니다\", \"zh-CN\": \"预览最多支持 10 张\", \"zh-TW\": \"預覽最多支援 10 張\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000922, 'basic', 'LABEL_PRINT_COUNT_REQUIRED', '{\"en-US\": \"Print count must be greater than 0\", \"ja-JP\": \"印刷枚数は0より大きい必要があります\", \"ko-KR\": \"인쇄 수량은 0보다 커야 합니다\", \"zh-CN\": \"打印张数必须大于 0\", \"zh-TW\": \"列印張數必須大於 0\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000923, 'basic', 'LABEL_PRINT_COUNT_LIMIT_EXCEEDED', '{\"en-US\": \"A single print job cannot exceed 1000 labels\", \"ja-JP\": \"1回の印刷は1000枚を超えることはできません\", \"ko-KR\": \"한 번에 1000장을 초과하여 인쇄할 수 없습니다\", \"zh-CN\": \"单次打印不能超过 1000 张\", \"zh-TW\": \"單次列印不能超過 1000 張\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000924, 'basic', 'LABEL_PRINT_DATA_INCOMPLETE', '{\"en-US\": \"Data is incomplete. Missing fields: {0}\", \"ja-JP\": \"データが不完全です。不足フィールド: {0}\", \"ko-KR\": \"데이터가 완전하지 않습니다. 누락 필드: {0}\", \"zh-CN\": \"数据不完整，缺少字段: {0}\", \"zh-TW\": \"資料不完整，缺少欄位: {0}\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000925, 'basic', 'LABEL_PRINT_RECORD_NOT_FOUND', '{\"en-US\": \"Print record does not exist\", \"ja-JP\": \"印刷記録が存在しません\", \"ko-KR\": \"인쇄 기록이 존재하지 않습니다\", \"zh-CN\": \"打印记录不存在\", \"zh-TW\": \"列印記錄不存在\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000926, 'excel', 'EXCEL_IMPORT_TEMPLATE_CONFIG_MISSING', '{\"en-US\": \"Import template configuration does not exist or import fields are not configured\", \"ja-JP\": \"インポートテンプレート設定が存在しないか、インポート項目が設定されていません\", \"ko-KR\": \"가져오기 템플릿 설정이 없거나 가져오기 필드가 설정되지 않았습니다\", \"zh-CN\": \"导入模板配置不存在或未配置导入字段\", \"zh-TW\": \"匯入模板設定不存在或未設定匯入欄位\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000927, 'excel', 'EXCEL_IMPORT_TEMPLATE_BUILD_FAILED', '{\"en-US\": \"Failed to generate import template: {0}\", \"ja-JP\": \"インポートテンプレートの生成に失敗しました: {0}\", \"ko-KR\": \"가져오기 템플릿 생성에 실패했습니다: {0}\", \"zh-CN\": \"生成导入模板失败: {0}\", \"zh-TW\": \"產生匯入模板失敗: {0}\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000928, 'sys', 'ROLE_INVALID_OR_CROSS_TENANT_SINGLE', '{\"en-US\": \"Role does not exist or does not belong to the current tenant\", \"ja-JP\": \"ロールが存在しないか、現在のテナントに属していません\", \"ko-KR\": \"역할이 존재하지 않거나 현재 테넌트에 속하지 않습니다\", \"zh-CN\": \"角色不存在或不属于当前租户\", \"zh-TW\": \"角色不存在或不屬於目前租戶\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000929, 'sys', 'ROLE_GRANT_TYPE_NOT_SUPPORTED', '{\"en-US\": \"Unsupported grant type: {0}\", \"ja-JP\": \"サポートされていない権限付与タイプです: {0}\", \"ko-KR\": \"지원하지 않는 권한 부여 유형입니다: {0}\", \"zh-CN\": \"不支持的授权类型：{0}\", \"zh-TW\": \"不支援的授權類型：{0}\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000930, 'sys', 'ROLE_GRANT_PART_DEPTS_NOT_FOUND', '{\"en-US\": \"Some departments do not exist\", \"ja-JP\": \"一部の部門が存在しません\", \"ko-KR\": \"일부 부서가 존재하지 않습니다\", \"zh-CN\": \"部分部门不存在\", \"zh-TW\": \"部分部門不存在\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000931, 'sys', 'ROLE_GRANT_PART_USERS_NOT_FOUND', '{\"en-US\": \"Some users do not exist\", \"ja-JP\": \"一部のユーザーが存在しません\", \"ko-KR\": \"일부 사용자가 존재하지 않습니다\", \"zh-CN\": \"部分用户不存在\", \"zh-TW\": \"部分使用者不存在\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000932, 'sys', 'MSG_TEMPLATE_CODE_REQUIRED', '{\"en-US\": \"Template code cannot be empty\", \"ja-JP\": \"テンプレートコードは空にできません\", \"ko-KR\": \"템플릿 코드는 비워둘 수 없습니다\", \"zh-CN\": \"模板编号不能为空\", \"zh-TW\": \"模板編號不能為空\"}', 1, 1, '20260427_business_exception_i18n', '2026-04-27 11:20:22', '20260427_business_exception_i18n', '2026-04-27 11:20:22', 0, NULL);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000933, 'excel', 'EXCEL_IMPORT_HANDLER_NOT_CONFIGURED', '{\"zh-CN\":\"导入处理器未配置\",\"en-US\":\"Import handler is not configured\",\"zh-TW\":\"匯入處理器未設定\",\"ja-JP\":\"インポートハンドラーが設定されていません\",\"ko-KR\":\"가져오기 처리기가 구성되지 않았습니다\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000934, 'excel', 'EXCEL_IMPORT_HANDLER_NOT_FOUND', '{\"zh-CN\":\"导入处理器不存在：{0}\",\"en-US\":\"Import handler does not exist: {0}\",\"zh-TW\":\"匯入處理器不存在：{0}\",\"ja-JP\":\"インポートハンドラーが存在しません：{0}\",\"ko-KR\":\"가져오기 처리기가 없습니다: {0}\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000935, 'excel', 'EXCEL_IMPORT_HANDLER_TYPE_INVALID', '{\"zh-CN\":\"导入处理器类型不正确：{0}\",\"en-US\":\"Import handler type is invalid: {0}\",\"zh-TW\":\"匯入處理器類型不正確：{0}\",\"ja-JP\":\"インポートハンドラーの型が正しくありません：{0}\",\"ko-KR\":\"가져오기 처리기 유형이 올바르지 않습니다: {0}\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000936, 'excel', 'EXCEL_IMPORT_DATA_EMPTY', '{\"zh-CN\":\"导入数据不能为空\",\"en-US\":\"Import data cannot be empty\",\"zh-TW\":\"匯入資料不能為空\",\"ja-JP\":\"インポートデータは空にできません\",\"ko-KR\":\"가져오기 데이터는 비워둘 수 없습니다\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000937, 'excel', 'EXCEL_IMPORT_MODE_INVALID', '{\"zh-CN\":\"导入方式无效\",\"en-US\":\"Import mode is invalid\",\"zh-TW\":\"匯入方式無效\",\"ja-JP\":\"インポート方式が無効です\",\"ko-KR\":\"가져오기 방식이 올바르지 않습니다\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000938, 'excel', 'EXCEL_IMPORT_PERMISSION_NOT_CONFIGURED', '{\"zh-CN\":\"导入权限码未配置\",\"en-US\":\"Import permission code is not configured\",\"zh-TW\":\"匯入權限碼未設定\",\"ja-JP\":\"インポート権限コードが設定されていません\",\"ko-KR\":\"가져오기 권한 코드가 구성되지 않았습니다\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000939, 'excel', 'EXCEL_IMPORT_PERMISSION_DENIED', '{\"zh-CN\":\"无导入权限\",\"en-US\":\"No import permission\",\"zh-TW\":\"無匯入權限\",\"ja-JP\":\"インポート権限がありません\",\"ko-KR\":\"가져오기 권한이 없습니다\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000940, 'excel', 'EXCEL_IMPORT_EXECUTE_SUCCESS', '{\"zh-CN\":\"导入完成：共{0}条，新增{1}条，修改{2}条，跳过{3}条，失败{4}条\",\"en-US\":\"Import completed: total {0}, created {1}, updated {2}, skipped {3}, failed {4}\",\"zh-TW\":\"匯入完成：共{0}筆，新增{1}筆，修改{2}筆，跳過{3}筆，失敗{4}筆\",\"ja-JP\":\"インポート完了：合計{0}件、追加{1}件、更新{2}件、スキップ{3}件、失敗{4}件\",\"ko-KR\":\"가져오기 완료: 총 {0}건, 신규 {1}건, 수정 {2}건, 건너뜀 {3}건, 실패 {4}건\"}', 1, 1, '20260501_common_import_upgrade', '2026-05-01 20:18:25', '20260501_common_import_upgrade', '2026-05-01 20:28:17', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000966, 'basic', 'UNIT_TYPE_CODE_EXISTS', '{\"en-US\": \"Unit type code already exists\", \"ja-JP\": \"計量単位タイプコードは既に存在します\", \"ko-KR\": \"계량 단위 유형 코드가 이미 존재합니다\", \"zh-CN\": \"计量单位类型编码已存在\", \"zh-TW\": \"計量單位類型編碼已存在\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000967, 'basic', 'UNIT_TYPE_NOT_FOUND', '{\"en-US\": \"Unit type does not exist\", \"ja-JP\": \"計量単位タイプが存在しません\", \"ko-KR\": \"계량 단위 유형이 존재하지 않습니다\", \"zh-CN\": \"计量单位类型不存在\", \"zh-TW\": \"計量單位類型不存在\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000968, 'basic', 'UNIT_TYPE_HAS_CHILDREN', '{\"en-US\": \"Child unit types exist under this unit type, deletion is not allowed\", \"ja-JP\": \"この計量単位タイプには子タイプがあるため削除できません\", \"ko-KR\": \"이 계량 단위 유형에 하위 유형이 있어 삭제할 수 없습니다\", \"zh-CN\": \"计量单位类型下存在子类型，禁止删除\", \"zh-TW\": \"計量單位類型下存在子類型，禁止刪除\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000969, 'basic', 'UNIT_TYPE_HAS_UNITS', '{\"en-US\": \"Units exist under this unit type, deletion is not allowed\", \"ja-JP\": \"この計量単位タイプには単位があるため削除できません\", \"ko-KR\": \"이 계량 단위 유형에 단위가 있어 삭제할 수 없습니다\", \"zh-CN\": \"计量单位类型下存在计量单位，禁止删除\", \"zh-TW\": \"計量單位類型下存在計量單位，禁止刪除\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000970, 'basic', 'UNIT_CODE_EXISTS', '{\"en-US\": \"Unit code already exists under the same type\", \"ja-JP\": \"同じタイプ内に計量単位コードが既に存在します\", \"ko-KR\": \"동일 유형에 계량 단위 코드가 이미 존재합니다\", \"zh-CN\": \"同类型下计量单位编码已存在\", \"zh-TW\": \"同類型下計量單位編碼已存在\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000971, 'basic', 'UNIT_NOT_FOUND', '{\"en-US\": \"Unit does not exist\", \"ja-JP\": \"計量単位が存在しません\", \"ko-KR\": \"계량 단위가 존재하지 않습니다\", \"zh-CN\": \"计量单位不存在\", \"zh-TW\": \"計量單位不存在\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000972, 'basic', 'UNIT_HAS_CONVERSION', '{\"en-US\": \"Unit conversion relations exist, deletion is not allowed\", \"ja-JP\": \"計量単位に換算関係があるため削除できません\", \"ko-KR\": \"계량 단위에 환산 관계가 있어 삭제할 수 없습니다\", \"zh-CN\": \"计量单位存在换算关系，禁止删除\", \"zh-TW\": \"計量單位存在換算關係，禁止刪除\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000973, 'basic', 'UNIT_CONVERSION_TARGET_INVALID', '{\"en-US\": \"Target unit must belong to the same type as the source unit\", \"ja-JP\": \"対象計量単位は元単位と同じタイプである必要があります\", \"ko-KR\": \"대상 계량 단위는 원본 단위와 같은 유형이어야 합니다\", \"zh-CN\": \"目标计量单位必须与源单位属于同一类型\", \"zh-TW\": \"目標計量單位必須與來源單位屬於同一類型\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000974, 'basic', 'UNIT_CONVERSION_RELATION_EXISTS', '{\"en-US\": \"Unit conversion relation already exists\", \"ja-JP\": \"計量単位の換算関係は既に存在します\", \"ko-KR\": \"계량 단위 환산 관계가 이미 존재합니다\", \"zh-CN\": \"计量单位换算关系已存在\", \"zh-TW\": \"計量單位換算關係已存在\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000975, 'basic', 'UNIT_CONVERSION_RELATION_NOT_FOUND', '{\"en-US\": \"Unit conversion relation does not exist\", \"ja-JP\": \"計量単位の換算関係が存在しません\", \"ko-KR\": \"계량 단위 환산 관계가 존재하지 않습니다\", \"zh-CN\": \"计量单位换算关系不存在\", \"zh-TW\": \"計量單位換算關係不存在\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000976, 'basic', 'UNIT_CONVERT_PARAM_INVALID', '{\"en-US\": \"Unit conversion parameters are incomplete\", \"ja-JP\": \"計量単位換算パラメータが不完全です\", \"ko-KR\": \"계량 단위 환산 매개변수가 완전하지 않습니다\", \"zh-CN\": \"计量单位换算参数不完整\", \"zh-TW\": \"計量單位換算參數不完整\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000977, 'basic', 'UNIT_CONVERT_FIELD_NOT_FOUND', '{\"en-US\": \"Unit conversion field does not exist: {0}\", \"ja-JP\": \"計量単位換算フィールドが存在しません：{0}\", \"ko-KR\": \"계량 단위 환산 필드가 존재하지 않습니다: {0}\", \"zh-CN\": \"计量单位换算字段不存在：{0}\", \"zh-TW\": \"計量單位換算欄位不存在：{0}\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000000978, 'basic', 'UNIT_CONVERT_FIELD_NOT_NUMBER', '{\"en-US\": \"Unit conversion field is not numeric: {0}\", \"ja-JP\": \"計量単位換算フィールドは数値ではありません：{0}\", \"ko-KR\": \"계량 단위 환산 필드가 숫자가 아닙니다: {0}\", \"zh-CN\": \"计量单位换算字段不是数字：{0}\", \"zh-TW\": \"計量單位換算欄位不是數字：{0}\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 20:54:41', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
