INSERT INTO `fx_i18n_message` VALUES (4000000000000001014, 'basic', 'basic.unit.typeTree', '{\"zh-CN\":\"单位类型树\",\"en-US\":\"Unit Type Tree\",\"zh-TW\":\"單位類型樹\",\"ja-JP\":\"単位タイプツリー\",\"ko-KR\":\"단위 유형 트리\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000001015, 'basic', 'basic.unit.typeTreeSub', '{\"zh-CN\":\"按类型维护单位主数据\",\"en-US\":\"Maintain unit master data by type\",\"zh-TW\":\"按類型維護單位主資料\",\"ja-JP\":\"タイプ別に単位マスタを管理\",\"ko-KR\":\"유형별 단위 마스터 데이터 관리\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000001016, 'basic', 'basic.unit.selectTypeHint', '{\"zh-CN\":\"请选择左侧计量单位类型\",\"en-US\":\"Select a unit type on the left\",\"zh-TW\":\"請選擇左側計量單位類型\",\"ja-JP\":\"左側の計量単位タイプを選択してください\",\"ko-KR\":\"왼쪽에서 계량 단위 유형을 선택하세요\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
