INSERT INTO `fx_i18n_message` VALUES (4000000000000001019, 'basic', 'basic.unit.requiredHint', '{\"zh-CN\":\"请完整填写必填项\",\"en-US\":\"Please complete all required fields\",\"zh-TW\":\"請完整填寫必填項\",\"ja-JP\":\"必須項目をすべて入力してください\",\"ko-KR\":\"필수 항목을 모두 입력하세요\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
INSERT INTO `fx_i18n_message` VALUES (4000000000000001020, 'basic', 'basic.unit.conversionRequiredHint', '{\"zh-CN\":\"请选择目标单位并填写大于 0 的转换数值\",\"en-US\":\"Select a target unit and enter a value greater than 0\",\"zh-TW\":\"請選擇目標單位並填寫大於 0 的轉換數值\",\"ja-JP\":\"目標単位を選択し、0 より大きい換算値を入力してください\",\"ko-KR\":\"대상 단위를 선택하고 0보다 큰 환산 값을 입력하세요\"}', 1, 1, '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', '20260502_basic_unit_and_table_upgrade', '2026-05-02 21:36:58', 0, 0);
